def guest_excel_data(df):
    """Excel para el interesado con precios y valor del inventario que permanece en Camelia."""
    out = io.BytesIO()
    visible = df.drop(
        columns=[
            "photo", "photo_name", "created_at", "updated_at", "created_by",
            "responsible_person", "transfer_date", "destination_detail",
        ],
        errors="ignore",
    ).copy()
    visible["Valor total"] = visible["quantity"] * visible["estimated_unit_value"]
    visible = visible.rename(columns={
        "id": "ID", "category": "Categoría", "subcategory": "Tipo",
        "item_name": "Artículo", "description": "Descripción", "quantity": "Cantidad",
        "unit": "Unidad", "brand": "Marca", "condition_status": "Estado",
        "current_area": "Ubicación actual", "location_summary": "Áreas de origen",
        "expiration_date": "Caducidad", "lot_number": "Lote",
        "estimated_unit_value": "Precio unitario", "destination": "Destino",
        "destination_summary": "Distribución", "transfer_status": "Estatus", "notes": "Notas",
    })
    with pd.ExcelWriter(out, engine="openpyxl") as writer:
        visible.to_excel(writer, index=False, sheet_name="Inventario Camelia")
        summary = df.assign(Valor=df.quantity * df.estimated_unit_value).groupby(
            "category", as_index=False
        ).agg(Registros=("id", "count"), Cantidad=("quantity", "sum"), Valor=("Valor", "sum")).rename(
            columns={"category": "Categoría"}
        )
        summary.to_excel(writer, index=False, sheet_name="Resumen categorías")
        ws = writer.book["Inventario Camelia"]
        headers = {cell.value: cell.column for cell in ws[1]}
        for header in ("Precio unitario", "Valor total"):
            if header in headers:
                col = headers[header]
                for row in range(2, ws.max_row + 1):
                    ws.cell(row=row, column=col).number_format = '$#,##0.00'
        ws2 = writer.book["Resumen categorías"]
        headers2 = {cell.value: cell.column for cell in ws2[1]}
        if "Valor" in headers2:
            col = headers2["Valor"]
            for row in range(2, ws2.max_row + 1):
                ws2.cell(row=row, column=col).number_format = '$#,##0.00'
    return out.getvalue()


def guest_dashboard(df):
    st.markdown(
        "<div class='hero'><small>Dossier de traspaso · V11 Executive</small>"
        "<h1>Inventario incluido en Camelia</h1>"
        "<p>Vista ejecutiva de los artículos y cantidades que permanecen en el establecimiento.</p></div>",
        unsafe_allow_html=True,
    )

    total = len(df)
    units = float(df["quantity"].sum()) if total else 0
    cats = int(df["category"].nunique()) if total else 0

    for col, data in zip(
        st.columns(3),
        [
            ("Artículos", f"{total:,}", "Registros incluidos"),
            ("Unidades", f"{units:,.0f}", "Existencia entregada"),
            ("Categorías", f"{cats:,}", "Tipos de inventario"),
        ],
    ):
        with col:
            metric(*data)

    if df.empty:
        st.info("Todavía no hay artículos incluidos.")
        return

    summary = (
        df.groupby("category", as_index=False)
        .agg(Registros=("id", "count"), Cantidad=("quantity", "sum"))
        .sort_values(["Cantidad", "Registros"], ascending=False)
    )

    st.markdown(
        "<div class='v10-section'><small>Composición del inventario</small>"
        "<h2>Resumen por categoría</h2></div>",
        unsafe_allow_html=True,
    )

    card_cols = st.columns(3)
    for index, row in summary.head(12).reset_index(drop=True).iterrows():
        with card_cols[index % 3]:
            st.markdown(
                f"<div class='summary-card'>"
                f"<small>{html.escape(str(row['category']))}</small>"
                f"<h3>{float(row['Cantidad']):,.0f}</h3>"
                f"<p>{int(row['Registros']):,} artículo(s)</p>"
                f"</div>",
                unsafe_allow_html=True,
            )

    st.markdown("#### Cantidad por categoría")
    max_quantity = max(float(summary["Cantidad"].max()), 1.0)
    rows_html = []
    for _, row in summary.head(12).iterrows():
        category = html.escape(str(row["category"]))
        quantity = float(row["Cantidad"])
        width = max(3.0, min(100.0, (quantity / max_quantity) * 100.0))
        rows_html.append(
            "<div class='hbar-row'>"
            f"<div class='hbar-label'>{category}</div>"
            "<div class='hbar-track'>"
            f"<div class='hbar-fill' style='width:{width:.2f}%'></div>"
            "</div>"
            f"<div class='hbar-value'>{quantity:,.0f} unidades</div>"
            "</div>"
        )
    st.markdown("<div class='hbar-wrap'>" + "".join(rows_html) + "</div>", unsafe_allow_html=True)

    st.markdown("#### Principales artículos por precio")
    sort_column = "_sort_unit_price" if "_sort_unit_price" in df.columns else "quantity"
    top = df.sort_values([sort_column, "quantity"], ascending=False).head(10)
    st.dataframe(
        top[["item_name", "category", "quantity", "unit"]].rename(
            columns={
                "item_name": "Artículo",
                "category": "Categoría",
                "quantity": "Cantidad",
                "unit": "Unidad",
            }
        ),
        hide_index=True,
        use_container_width=True,
        height=390,
    )



def guest_pdf_data(df):
    """Genera el documento PDF del inventario del invitado sin precios ni valores."""
    from reportlab.lib import colors
    from reportlab.lib.enums import TA_CENTER, TA_LEFT
    from reportlab.lib.pagesizes import landscape, letter
    from reportlab.lib.styles import ParagraphStyle, getSampleStyleSheet
    from reportlab.lib.units import inch
    from reportlab.platypus import (
        KeepTogether, PageBreak, Paragraph, SimpleDocTemplate, Spacer, Table, TableStyle
    )

    output = io.BytesIO()
    doc = SimpleDocTemplate(
        output,
        pagesize=landscape(letter),
        rightMargin=28, leftMargin=28, topMargin=30, bottomMargin=30,
        title="Inventario incluido en Camelia",
        author="Camelia Modern Mexican Cuisine",
    )
    styles = getSampleStyleSheet()
    title_style = ParagraphStyle(
        "CameliaTitle", parent=styles["Title"], fontName="Helvetica-Bold",
        fontSize=22, leading=26, textColor=colors.HexColor("#2F3A32"),
        alignment=TA_CENTER, spaceAfter=8,
    )
    subtitle_style = ParagraphStyle(
        "CameliaSubtitle", parent=styles["Normal"], fontSize=10, leading=14,
        textColor=colors.HexColor("#6B6256"), alignment=TA_CENTER, spaceAfter=14,
    )
    section_style = ParagraphStyle(
        "CameliaSection", parent=styles["Heading2"], fontName="Helvetica-Bold",
        fontSize=13, leading=16, textColor=colors.HexColor("#2F3A32"),
        spaceBefore=8, spaceAfter=8,
    )
    body_style = ParagraphStyle(
        "CameliaBody", parent=styles["BodyText"], fontSize=7.5, leading=9.5,
        alignment=TA_LEFT, textColor=colors.HexColor("#2B2925"),
    )
    small_style = ParagraphStyle(
        "CameliaSmall", parent=styles["BodyText"], fontSize=7, leading=8.5,
        alignment=TA_LEFT, textColor=colors.HexColor("#2B2925"),
    )

    story = [
        Paragraph("CAMELIA MODERN MEXICAN CUISINE", title_style),
        Paragraph(
            "Documento de entrega · Inventario incluido sin precios ni valores monetarios<br/>"
            f"Generado el {date.today().strftime('%d/%m/%Y')}",
            subtitle_style,
        ),
    ]

    total_items = len(df)
    total_units = float(df["quantity"].sum()) if total_items else 0
    total_categories = int(df["category"].nunique()) if total_items else 0
    metrics = Table(
        [
            ["ARTÍCULOS", "UNIDADES", "CATEGORÍAS"],
            [f"{total_items:,}", f"{total_units:,.0f}", f"{total_categories:,}"],
        ],
        colWidths=[2.35 * inch] * 3,
        hAlign="CENTER",
    )
    metrics.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#2F3A32")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("BACKGROUND", (0, 1), (-1, 1), colors.HexColor("#F4EFE5")),
        ("TEXTCOLOR", (0, 1), (-1, 1), colors.HexColor("#2F3A32")),
        ("FONTNAME", (0, 0), (-1, -1), "Helvetica-Bold"),
        ("FONTSIZE", (0, 0), (-1, 0), 8),
        ("FONTSIZE", (0, 1), (-1, 1), 16),
        ("ALIGN", (0, 0), (-1, -1), "CENTER"),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
        ("BOX", (0, 0), (-1, -1), 0.6, colors.HexColor("#C9AD69")),
        ("INNERGRID", (0, 0), (-1, -1), 0.3, colors.HexColor("#D9CBAA")),
        ("TOPPADDING", (0, 0), (-1, -1), 7),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 7),
    ]))
    story.extend([metrics, Spacer(1, 14), Paragraph("Resumen por categoría", section_style)])

    summary = (
        df.groupby("category", as_index=False)
        .agg(Registros=("id", "count"), Cantidad=("quantity", "sum"))
        .sort_values(["Cantidad", "Registros"], ascending=False)
    )
    summary_data = [["Categoría", "Artículos", "Cantidad"]]
    for _, row in summary.iterrows():
        summary_data.append([
            Paragraph(html.escape(str(row["category"])), body_style),
            f"{int(row['Registros']):,}",
            f"{float(row['Cantidad']):,.0f}",
        ])
    summary_table = Table(summary_data, colWidths=[4.7 * inch, 1.15 * inch, 1.25 * inch], repeatRows=1)
    summary_table.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#2F3A32")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("ALIGN", (1, 1), (-1, -1), "RIGHT"),
        ("VALIGN", (0, 0), (-1, -1), "TOP"),
        ("GRID", (0, 0), (-1, -1), 0.35, colors.HexColor("#D9CBAA")),
        ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.white, colors.HexColor("#F8F5EE")]),
        ("TOPPADDING", (0, 0), (-1, -1), 5),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 5),
        ("FONTSIZE", (0, 0), (-1, -1), 8),
    ]))
    story.extend([summary_table, PageBreak(), Paragraph("Detalle del inventario", section_style)])

    headers = ["ID", "Categoría", "Tipo", "Artículo", "Marca", "Cantidad", "Unidad", "Estado", "Áreas de origen", "Notas"]
    table_data = [headers]
    for _, row in df.sort_values(["category", "item_name", "id"]).iterrows():
        table_data.append([
            str(int(row["id"])),
            Paragraph(html.escape(str(row.get("category", ""))), small_style),
            Paragraph(html.escape(str(row.get("subcategory", ""))), small_style),
            Paragraph(html.escape(str(row.get("item_name", ""))), small_style),
            Paragraph(html.escape(str(row.get("brand", ""))), small_style),
            f"{float(row.get('quantity', 0)):,.2f}".rstrip("0").rstrip("."),
            Paragraph(html.escape(str(row.get("unit", ""))), small_style),
            Paragraph(html.escape(str(row.get("condition_status", ""))), small_style),
            Paragraph(html.escape(str(row.get("location_summary", ""))), small_style),
            Paragraph(html.escape(str(row.get("notes", ""))), small_style),
        ])
    widths = [0.38, 0.82, 0.78, 1.38, 0.72, 0.55, 0.55, 0.72, 1.35, 1.35]
    detail_table = Table(table_data, colWidths=[x * inch for x in widths], repeatRows=1)
    detail_table.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#2F3A32")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("FONTSIZE", (0, 0), (-1, 0), 6.8),
        ("ALIGN", (0, 1), (0, -1), "CENTER"),
        ("ALIGN", (5, 1), (5, -1), "RIGHT"),
        ("VALIGN", (0, 0), (-1, -1), "TOP"),
        ("GRID", (0, 0), (-1, -1), 0.25, colors.HexColor("#D9CBAA")),
        ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.white, colors.HexColor("#F8F5EE")]),
        ("TOPPADDING", (0, 0), (-1, -1), 4),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 4),
        ("LEFTPADDING", (0, 0), (-1, -1), 3),
        ("RIGHTPADDING", (0, 0), (-1, -1), 3),
    ]))
    story.append(detail_table)

    def footer(canvas, doc_obj):
        canvas.saveState()
        canvas.setStrokeColor(colors.HexColor("#C9AD69"))
        canvas.line(28, 22, landscape(letter)[0] - 28, 22)
        canvas.setFont("Helvetica", 7)
        canvas.setFillColor(colors.HexColor("#6B6256"))
        canvas.drawString(28, 11, "Camelia Modern Mexican Cuisine · Documento de entrega")
        canvas.drawRightString(landscape(letter)[0] - 28, 11, f"Página {doc_obj.page}")
        canvas.restoreState()

    doc.build(story, onFirstPage=footer, onLaterPages=footer)
    output.seek(0)
    return output.getvalue()

def guest_reports(df):
    st.markdown(
        "<div class='hero'><small>Documentación de entrega</small>"
        "<h1>Relación del inventario</h1>"
        "<p>Descarga los documentos disponibles para revisión, impresión o presentación.</p></div>",
        unsafe_allow_html=True,
    )
    if df.empty:
        st.info("No hay artículos disponibles para descargar.")
        return

    export = df.drop(columns=["photo", "estimated_unit_value", "_sort_unit_price"], errors="ignore").copy()
    preferred = [
        "id", "category", "subcategory", "item_name", "description", "brand",
        "quantity", "unit", "condition_status", "location_summary",
        "destination_summary", "transfer_status", "notes"
    ]
    export = export[[c for c in preferred if c in export.columns]].rename(columns={
        "id": "ID", "category": "Categoría", "subcategory": "Tipo",
        "item_name": "Artículo", "description": "Descripción", "brand": "Marca",
        "quantity": "Cantidad", "unit": "Unidad", "condition_status": "Estado",
        "location_summary": "Áreas de origen", "destination_summary": "Destino",
        "transfer_status": "Estatus", "notes": "Notas",
    })

    excel_buffer = io.BytesIO()
    with pd.ExcelWriter(excel_buffer, engine="openpyxl") as writer:
        export.to_excel(writer, index=False, sheet_name="Inventario incluido")
        summary = (
            df.groupby("category", as_index=False)
            .agg(Registros=("id", "count"), Cantidad=("quantity", "sum"))
            .rename(columns={"category": "Categoría"})
        )
        summary.to_excel(writer, index=False, sheet_name="Resumen categorías")
        from openpyxl.styles import Alignment, Font, PatternFill
        from openpyxl.utils import get_column_letter
        header_fill = PatternFill("solid", fgColor="2F3A32")
        header_font = Font(color="FFFFFF", bold=True)
        for ws in writer.book.worksheets:
            ws.freeze_panes = "A2"
            ws.auto_filter.ref = ws.dimensions
            for cell in ws[1]:
                cell.fill = header_fill
                cell.font = header_font
                cell.alignment = Alignment(horizontal="center", vertical="center")
            for column_cells in ws.columns:
                max_length = max(len(str(cell.value or "")) for cell in column_cells)
                ws.column_dimensions[get_column_letter(column_cells[0].column)].width = min(max(max_length + 2, 11), 42)
            for row in ws.iter_rows(min_row=2):
                for cell in row:
                    cell.alignment = Alignment(vertical="top", wrap_text=True)

    pdf_data = None
    pdf_error = None
    try:
        pdf_data = guest_pdf_data(df)
    except ModuleNotFoundError as exc:
        if exc.name == "reportlab" or str(exc.name).startswith("reportlab"):
            pdf_error = "El generador de PDF todavía no está disponible. Verifica requirements.txt y reinicia la aplicación."
        else:
            raise
    except Exception as exc:
        pdf_error = f"No fue posible generar el PDF: {exc}"

    c1, c2 = st.columns(2)
    with c1:
        st.markdown(
            "<div class='v10-doc'><h3>Excel de entrega</h3>"
            "<p>Inventario editable con resumen por categoría.</p></div>",
            unsafe_allow_html=True,
        )
        st.download_button(
            "Descargar Excel",
            excel_buffer.getvalue(),
            f"Inventario_Entrega_Camelia_{date.today().isoformat()}.xlsx",
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            use_container_width=True,
        )
    with c2:
        st.markdown(
            "<div class='v10-doc'><h3>PDF de entrega</h3>"
            "<p>Documento formal con resumen y detalle del inventario.</p></div>",
            unsafe_allow_html=True,
        )
        if pdf_data is not None:
            st.download_button(
                "Descargar PDF",
                pdf_data,
                f"Documento_Entrega_Camelia_{date.today().isoformat()}.pdf",
                "application/pdf",
                use_container_width=True,
            )
        else:
            st.warning(pdf_error or "El PDF no está disponible temporalmente.")

def guest_inventory(df):
    st.markdown("## Inventario incluido")
    st.caption("Selecciona un artículo para consultar su fotografía y la información disponible. Consulta la fotografía y la información disponible del artículo.")
    filtered = filter_df(df, "guest_inv_")
    if filtered.empty:
        st.info("No hay artículos que coincidan con los filtros.")
        return

    table = filtered.copy().rename(columns={
        "id": "ID", "category": "Categoría", "subcategory": "Tipo",
        "item_name": "Artículo", "brand": "Marca", "quantity": "Cantidad",
        "unit": "Unidad", "condition_status": "Estado",
    })
    columns = ["ID", "Categoría", "Tipo", "Artículo", "Marca", "Cantidad", "Unidad", "Estado"]
    st.dataframe(
        table[columns], use_container_width=True, hide_index=True, height=430,
        column_config={
            "ID": st.column_config.NumberColumn(width="small"),
            "Artículo": st.column_config.TextColumn(width="large"),
        },
    )
    st.caption(f"Mostrando {len(filtered)} de {len(df)} registros incluidos en Camelia.")

    st.markdown("### Consultar artículo")
    choices = {
        f"#{int(r.id)} · {r.item_name} · {r.quantity:g} {r.unit}": int(r.id)
        for _, r in filtered.sort_values(["item_name", "id"]).iterrows()
    }
    selected_label = st.selectbox("Artículo inventariado", list(choices.keys()))
    selected = filtered[filtered.id.eq(choices[selected_label])].iloc[0]

    c1, c2 = st.columns([1, 2])
    with c1:
        photo = selected.get("photo")
        if photo is not None and not pd.isna(photo):
            st.image(photo, use_container_width=True, caption=selected.item_name)
        else:
            st.info("Este artículo no tiene fotografía registrada.")
    with c2:
        st.markdown(f"### {selected.item_name}")
        m1, m2, m3 = st.columns(3)
        with m1:
            metric("Cantidad", f"{selected.quantity:g} {selected.unit}", "Permanece en Camelia")
        with m2:
            metric("Categoría", str(selected.category), "Clasificación")
        with m3:
            metric("Estado", str(selected.condition_status), "Condición registrada")
        st.markdown(f"**Tipo:** {selected.subcategory}")
        st.markdown(f"**Marca:** {selected.brand or 'Sin marca'}")
        st.markdown(f"**Áreas de origen:** {selected.get('location_summary') or selected.current_area or 'No especificadas'}")
        if selected.description:
            st.markdown(f"**Descripción:** {selected.description}")
        if selected.notes:
            st.markdown(f"**Notas:** {selected.notes}")


def main():
    init_db()
    if "user" not in st.session_state:
        login()
        return

    st.markdown(f"<div class='top-logo-wrap'>{camelia_logo_html()}</div>", unsafe_allow_html=True)
    c1, c2 = st.columns([4, 1])
    role = st.session_state.user["role"]
    role_label = {"admin": "ADMINISTRADOR", "viewer": "PROPIETARIA", "guest": "INVITADO"}.get(role, role.upper())
    with c1:
        st.caption(f"Sesión: {st.session_state.user['name']} · {role_label}")
    with c2:
        if st.button("Cerrar sesión", use_container_width=True):
            st.session_state.pop("user", None)
            st.rerun()

    df = load_df()

    if role == "guest":
        guest_df = df[df["camelia_quantity"].gt(0)].copy()
        guest_df["quantity"] = guest_df["camelia_quantity"]
        guest_df["destination"] = "Camelia · permanece en el local"
        guest_df["destination_summary"] = "Camelia · permanece en el local"
        # Se conserva una columna interna únicamente para ordenar el Top de artículos.
        # No se muestra ni se exporta al invitado.
        if "estimated_unit_value" in guest_df.columns:
            guest_df["_sort_unit_price"] = guest_df["estimated_unit_value"].fillna(0)
        else:
            guest_df["_sort_unit_price"] = 0
        # Protección adicional: la vista del invitado no recibe la columna visible de precios.
        guest_df = guest_df.drop(columns=["estimated_unit_value"], errors="ignore")
        options = ["Inicio", "Inventario incluido", "Documento de entrega"]
        page = st.radio("Navegación", options, horizontal=True, label_visibility="collapsed")
        if page == "Inicio":
            guest_dashboard(guest_df)
        elif page == "Inventario incluido":
            guest_inventory(guest_df)
        else:
            guest_reports(guest_df)
        return

    admin = role == "admin"
    options = ["Resumen", "Inventario", "Destinos", "Caducidades", "Reportes"]
    if admin:
        options.insert(1, "Registrar artículo")
        options.append("Respaldos")
    page = st.radio("Navegación", options, horizontal=True, label_visibility="collapsed")
    if page == "Resumen":
        dashboard(df)
    elif page == "Registrar artículo":
        st.markdown("## Registrar nuevo artículo")
        st.caption("Para vinos y licores, registra una sola ficha por etiqueta y reparte las cantidades entre áreas y destinos.")
        values = form()
        if values:
            sid = save_item(values, st.session_state.user["name"])
            st.success(f"Artículo guardado con folio #{sid}.")
            st.rerun()
    elif page == "Inventario":
        inventory(df, admin)
    elif page == "Destinos":
        destinations(df)
    elif page == "Caducidades":
        expirations(df)
    elif page == "Reportes":
        reports(df)
    elif page == "Respaldos" and admin:
        admin_backup_page()
    else:
        reports(df)


if __name__ == "__main__":
    main()
